import React, { useState, useEffect } from 'react';
import axios from 'axios';
import Header from '../components/Header'; 
import Footer from '../components/Footer';

export default function Marketplace() {
  // ✅ 1. State to track which view to show
  const [view, setView] = useState('marketplace'); 
  const [activeTab, setActiveTab] = useState('all'); 
  const [loads, setLoads] = useState([]);
  const [form, setForm] = useState({ origin: '', destination: '', weight: '', pallets: '', price: '' });
  const [loading, setLoading] = useState(false);

  const currentUser = localStorage.getItem("userName") || "Guest"; 

  const fetchData = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/loads/all");
      setLoads(res.data);
    } catch (err) { console.error("Fetch Error:", err); }
  };

  useEffect(() => { 
    if (view === 'marketplace' || view === 'find-loads') fetchData(); 
  }, [view]);

  const handlePost = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await axios.post("http://localhost:5000/api/loads/add", { ...form, postedBy: currentUser });
      setForm({ origin: '', destination: '', weight: '', pallets: '', price: '' });
      fetchData();
      setView('marketplace'); // Post panna thooku marketplace-ku kooptu pogum
    } catch (err) { alert("Error posting load"); }
    setLoading(false);
  };

  const displayedLoads = activeTab === 'all' 
    ? loads 
    : loads.filter(l => l.postedBy === currentUser);

  // ✅ 2. Sub-Components for Different Views
  const renderContent = () => {
    switch(view) {
      case 'privacy':
        return (
          <div className="bg-white/80 backdrop-blur-lg p-12 rounded-[3rem] shadow-2xl border border-white">
            <h2 className="text-3xl font-black uppercase italic mb-6">Privacy Policy</h2>
            <p className="text-slate-600 leading-relaxed">We value your privacy at Truck Board Pro. We only collect data necessary for logistics operations and ensure all your shipment details are encrypted. Your location data is used only for matching loads.</p>
            <button onClick={() => setView('marketplace')} className="mt-8 text-red-600 font-bold uppercase underline">Back to Board</button>
          </div>
        );
      case 'terms':
        return (
          <div className="bg-white/80 backdrop-blur-lg p-12 rounded-[3rem] shadow-2xl border border-white">
            <h2 className="text-3xl font-black uppercase italic mb-6">Terms of Service</h2>
            <ul className="list-disc ml-6 space-y-4 text-slate-600">
              <li>Users must provide accurate weight and pallet counts.</li>
              <li>Payments are settled directly between carriers and shippers.</li>
              <li>Truck Board Pro is not liable for cargo damage during transit.</li>
            </ul>
            <button onClick={() => setView('marketplace')} className="mt-8 text-red-600 font-bold uppercase underline">Back to Board</button>
          </div>
        );
      case 'contact':
        return (
          <div className="bg-white/80 backdrop-blur-lg p-12 rounded-[3rem] shadow-2xl border border-white text-center">
            <h2 className="text-3xl font-black uppercase italic mb-4">Support Center</h2>
            <p className="text-xl font-bold text-slate-800 mb-2">Need help with a shipment?</p>
            <p className="text-red-600 text-2xl font-black">support@truckboardpro.com</p>
            <p className="mt-4 text-slate-500">Available 24/7 for active dispatchers.</p>
            <button onClick={() => setView('marketplace')} className="mt-8 text-slate-900 font-bold uppercase underline">Close Support</button>
          </div>
        );
      default:
        return (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
            {/* SIDEBAR FORM */}
            <aside className="lg:col-span-4">
              <div className="sticky top-28 bg-white/70 backdrop-blur-xl rounded-[2.5rem] shadow-2xl border border-white/50 overflow-hidden">
                <div className="bg-slate-900 p-8 text-center">
                    <h2 className="text-white text-xl font-black uppercase italic tracking-widest">Post Freight</h2>
                    <div className="h-1 w-12 bg-red-600 mx-auto mt-2 rounded-full"></div>
                </div>
                <form onSubmit={handlePost} className="p-8 space-y-4">
                  <input type="text" placeholder="Origin" className="w-full p-4 bg-white/50 rounded-2xl border-2 border-transparent focus:border-red-600 outline-none font-bold" value={form.origin} onChange={e => setForm({...form, origin: e.target.value})} required />
                  <input type="text" placeholder="Destination" className="w-full p-4 bg-white/50 rounded-2xl border-2 border-transparent focus:border-red-600 outline-none font-bold" value={form.destination} onChange={e => setForm({...form, destination: e.target.value})} required />
                  <div className="grid grid-cols-2 gap-4">
                    <input type="number" placeholder="Kg" className="w-full p-4 bg-white/50 rounded-2xl border-2 border-transparent focus:border-red-600 outline-none font-bold" value={form.weight} onChange={e => setForm({...form, weight: e.target.value})} required />
                    <input type="number" placeholder="Plt" className="w-full p-4 bg-white/50 rounded-2xl border-2 border-transparent focus:border-red-600 outline-none font-bold" value={form.pallets} onChange={e => setForm({...form, pallets: e.target.value})} required />
                  </div>
                  <input type="number" placeholder="Price $" className="w-full p-4 bg-white/50 rounded-2xl border-2 border-transparent focus:border-green-500 outline-none font-bold text-green-600" value={form.price} onChange={e => setForm({...form, price: e.target.value})} required />
                  <button disabled={loading} className="w-full bg-[#E11D48] text-white py-5 rounded-2xl font-black uppercase tracking-widest hover:bg-slate-900 transition-all">
                    {loading ? 'Broadcasting...' : 'Post Load'}
                  </button>
                </form>
              </div>
            </aside>

            {/* MAIN FEED */}
            <section className="lg:col-span-8">
              <div className="flex justify-between items-center mb-8">
                <div className="bg-white/60 backdrop-blur-md p-1.5 rounded-2xl shadow-lg flex border border-white/50">
                  <button onClick={() => setActiveTab('all')} className={`px-8 py-3 rounded-xl font-black text-xs uppercase tracking-widest transition-all ${activeTab === 'all' ? 'bg-[#E11D48] text-white' : 'text-slate-500'}`}>Live Loads</button>
                  <button onClick={() => setActiveTab('mine')} className={`px-8 py-3 rounded-xl font-black text-xs uppercase tracking-widest transition-all ${activeTab === 'mine' ? 'bg-[#E11D48] text-white' : 'text-slate-500'}`}>My Posts</button>
                </div>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {displayedLoads.map(l => (
                   <div key={l._id} className="bg-white/80 backdrop-blur-lg rounded-[2.5rem] p-8 border-2 border-white shadow-2xl">
                      <div className="flex justify-between items-start mb-6">
                        <span className="bg-yellow-400 text-[9px] font-black px-4 py-1.5 rounded-full uppercase italic">Available</span>
                        <div className="text-3xl font-black text-slate-900">${l.price}</div>
                      </div>
                      <h3 className="text-xl font-black text-slate-800 uppercase">{l.origin} ➔ {l.destination}</h3>
                      <p className="text-xs font-bold text-slate-400 mt-2 uppercase tracking-widest">{l.weight} KG • {l.pallets} Pallets</p>
                   </div>
                ))}
              </div>
            </section>
          </div>
        );
    }
  };

  return (
    <div className="min-h-screen flex flex-col relative font-sans text-slate-900 overflow-x-hidden">
      
      {/* BACKGROUND */}
      <div className="fixed inset-0" style={{ backgroundImage: `url('https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?ixlib=rb-4.0.3&auto=format&fit=crop&w=2000&q=80')`, backgroundSize: 'cover', backgroundPosition: 'center', zIndex: -1 }}>
        <div className="absolute inset-0 bg-[#FFFBEB]/85 backdrop-blur-[3px]"></div>
      </div>

      {/* ✅ 3. Passing setView to Header so clicks work */}
      <div className="relative z-[100]">
         <Header setView={setView} />
      </div>

      <main className="relative z-10 flex-grow max-w-[1400px] mx-auto p-8 w-full mt-5">
         {renderContent()}
      </main>

      {/* ✅ 4. Passing setView to Footer so links work */}
      <div className="relative z-[100]">
        <Footer setView={setView} />
      </div>

    </div>
  );
}
